// Fidely landing — main app
const { useState, useEffect, useRef } = React;

// ---------- Icons ----------
const Icon = ({ name, size = 18, ...rest }) => {
  const s = size;
  const stroke = { fill: 'none', stroke: 'currentColor', strokeWidth: 2, strokeLinecap: 'round', strokeLinejoin: 'round' };
  switch (name) {
    case 'arrow-right':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M5 12h14M13 5l7 7-7 7" /></svg>;
    case 'arrow-down':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M12 5v14M5 13l7 7 7-7" /></svg>;
    case 'check':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M20 6 9 17l-5-5" /></svg>;
    case 'plus':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M12 5v14M5 12h14" /></svg>;
    case 'star':return <svg width={s} height={s} viewBox="0 0 24 24" fill="currentColor" {...rest}><path d="M12 2l3 7 7 .8-5.3 4.7 1.6 7-6.3-3.7L5.7 21.5l1.6-7L2 9.8 9 9z" /></svg>;
    case 'gift':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M20 12v10H4V12M2 7h20v5H2zM12 22V7M12 7H7.5A2.5 2.5 0 0 1 7.5 2C11 2 12 7 12 7zM12 7h4.5A2.5 2.5 0 0 0 16.5 2C13 2 12 7 12 7z" /></svg>;
    case 'users':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75M8.5 11a4 4 0 1 0 0-8 4 4 0 0 0 0 8z" /></svg>;
    case 'cal':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><rect x="3" y="4" width="18" height="18" rx="2" /><path d="M16 2v4M8 2v4M3 10h18" /></svg>;
    case 'card':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><rect x="2" y="5" width="20" height="14" rx="2" /><path d="M2 10h20" /></svg>;
    case 'bell':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M18 8a6 6 0 1 0-12 0c0 7-3 9-3 9h18s-3-2-3-9M13.7 21a2 2 0 0 1-3.4 0" /></svg>;
    case 'chart':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M3 3v18h18M7 14l4-4 4 4 5-6" /></svg>;
    case 'whatsapp':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M3 21l1.65-3.8A9 9 0 1 1 8.5 20.4L3 21M9 10a.5.5 0 0 0 1 0V9a.5.5 0 0 0-1 0v1a5 5 0 0 0 5 5h1a.5.5 0 0 0 0-1h-1" /></svg>;
    case 'instagram':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><rect x="2" y="2" width="20" height="20" rx="5" /><path d="M16 11.4A4 4 0 1 1 12.6 8 4 4 0 0 1 16 11.4zM17.5 6.5h.01" /></svg>;
    case 'menu':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M3 6h18M3 12h18M3 18h18" /></svg>;
    case 'spark':return <svg width={s} height={s} viewBox="0 0 24 24" {...stroke} {...rest}><path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2 2M16.4 16.4l2 2M5.6 18.4l2-2M16.4 7.6l2-2" /></svg>;
    default:return null;
  }
};

