// ---------- NAV ----------
function Nav() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 12);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  return (
    <div className={`nav-wrap ${scrolled ? 'scrolled' : ''}`}>
      <div className="container nav">
        <a href="#top" aria-label="Fidely" style={{ display: 'flex', alignItems: 'center' }}><FidelyLogo height={32} /></a>
        <div className="nav-links">
          <a href="#producto">Producto</a>
          <a href="#como-funciona">Cómo funciona</a>
          <a href="#precios">Precios</a>
          <a href="#founders">Plan Founders</a>
          <a href="/blog">Blog</a>
        </div>
        <div className="nav-cta-wrap">
          <a href="#cta" className="btn btn-primary">Solicitar demo <Icon name="arrow-right" size={15} /></a>
        </div>
        <button className="nav-burger" aria-label="Menú"><Icon name="menu" /></button>
      </div>
    </div>);

}

