// ---------- METRICS BAR ----------
function MetricsBar() {
  const items = [
  { n: '+46%', l: 'gasto por cliente con membresía' },
  { n: '+57%', l: 'más referidos automáticos' },
  { n: '+132%', l: 'más reseñas en Google' },
  { n: 'x3', l: 'valoración del negocio con MRR predecible' }];

  return (
    <section className="metrics-bar" style={{ padding: '56px 0 44px' }}>
      <div className="container">
        <div className="metrics-row">
          {items.map((it, i) => {
            const m = it.n.match(/^([+x])(.+)$/);
            return (
              <div className="metric" key={i}>
                <div className="metric-num">
                  {m ? <><span className="sym">{m[1]}</span>{m[2]}</> : it.n}
                </div>
                <div className="metric-label">{it.l}</div>
              </div>);

          })}
        </div>
        <div className="metrics-foot">Métricas de referencia — DermisApp UK en clínicas estéticas similares a la tuya.</div>
      </div>
    </section>);

}

