function StepIllus({ n }) {
  if (n === 1) return (
    <div className="step-illus" style={{ display: 'flex', gap: 10, alignItems: 'center', justifyContent: 'center' }}>
      <div className="illus-card" style={{ width: 90, height: 160, borderRadius: 18, padding: 8, background: '#1B2340' }}>
        <div style={{ width: '100%', height: '100%', background: 'linear-gradient(160deg,#E8F8F0,white)', borderRadius: 12, padding: 10, display: 'flex', flexDirection: 'column', gap: 6 }}>
          <div className="illus-bar green" style={{ width: '40%' }} />
          <div className="illus-bar" style={{ width: '70%' }} />
          <div className="illus-bar" style={{ width: '55%' }} />
        </div>
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        <div style={{ width: 30, height: 30, borderRadius: 8, background: '#2ECC71' }} />
        <div style={{ width: 30, height: 30, borderRadius: 8, background: '#1B2340' }} />
        <div style={{ width: 30, height: 30, borderRadius: 8, background: '#E8F8F0', border: '1px solid #2ECC71' }} />
      </div>
    </div>);

  if (n === 2) return (
    <div className="illus-card" style={{ width: '80%', padding: 14 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 10 }}>
        <div className="illus-bar navy" style={{ width: 60, height: 6 }} />
        <div className="illus-bar" style={{ width: 24, height: 6 }} />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 6, marginBottom: 10 }}>
        {[1, 2, 3].map((i) => <div key={i} style={{ height: 36, borderRadius: 6, background: i === 2 ? '#1B2340' : '#F7F8FA' }} />)}
      </div>
      <div className="illus-bar green" style={{ width: '70%', height: 6, marginBottom: 6 }} />
      <div className="illus-bar" style={{ width: '50%', height: 6 }} />
    </div>);

  return (
    <div className="illus-card" style={{ width: '80%', padding: 16 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 14 }}>
        <div>
          <div style={{ fontSize: 10, color: '#6B7280' }}>MRR</div>
          <div style={{ fontFamily: 'Playfair Display', fontSize: 20, fontWeight: 600, color: '#1B2340' }}>4.860€</div>
        </div>
        <div style={{ fontSize: 10, color: '#27AE60', fontWeight: 600, padding: '2px 8px', background: '#E8F8F0', borderRadius: 999, height: 'fit-content' }}>+18%</div>
      </div>
      <svg width="100%" height="50" viewBox="0 0 200 50" preserveAspectRatio="none">
        <path d="M0 42 L30 38 L60 30 L90 32 L120 22 L150 18 L180 10 L200 6" fill="none" stroke="#2ECC71" strokeWidth="2.5" strokeLinecap="round" />
        <path d="M0 42 L30 38 L60 30 L90 32 L120 22 L150 18 L180 10 L200 6 L200 50 L0 50 Z" fill="#2ECC71" opacity="0.1" />
      </svg>
    </div>);

}

