// ---------- FORM ENDPOINT ----------
const FIDELY_WEBHOOK = 'https://script.google.com/macros/s/AKfycbx5xy4C2kTZyDTa9RcrbGOeMxFIVzxwn-EC67UujZ7LL-P8a2Xg4Aiae5pic_HRRt0IDQ/exec';

async function sendToFidely(data) {
  try {
    await fetch(FIDELY_WEBHOOK, {
      method: 'POST',
      mode: 'no-cors',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify(data)
    });
    return true;
  } catch (err) {
    console.error('Webhook error', err);
    return false;
  }
}

// ---------- FINAL CTA ----------
function FinalCTA() {
  const [sent, setSent] = useState(false);
  const [sending, setSending] = useState(false);
  const [form, setForm] = useState({ clinica: '', nombre: '', email: '', telefono: '' });
  const [errors, setErrors] = useState({ email: '', telefono: '' });
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;
  const telRe = /^\+?[\d\s]{9,15}$/;
  const update = (k) => (e) => {
    const val = e.target.value;
    setForm(prev => ({ ...prev, [k]: val }));
    if (k === 'email' || k === 'telefono') setErrors(prev => ({ ...prev, [k]: '' }));
  };
  const submit = async (e) => {
    e.preventDefault();
    const newErrors = { email: '', telefono: '' };
    if (!emailRe.test(form.email)) newErrors.email = 'Introduce un email válido (ejemplo: nombre@clinica.es)';
    if (!telRe.test(form.telefono)) newErrors.telefono = 'Introduce un teléfono válido (mínimo 9 dígitos)';
    if (newErrors.email || newErrors.telefono) { setErrors(newErrors); return; }
    setSending(true);
    await sendToFidely({ ...form, origen: 'CTA Final' });
    setSending(false);
    setSent(true);
  };
  const errStyle = { color: '#DC2626', fontSize: 12, fontFamily: "'DM Sans',sans-serif", marginTop: 4, display: 'block' };
  return (
    <section className="final-cta" id="cta">
      <div className="container">
        <div className="section-head">
          <span className="eyebrow">Empieza hoy</span>
          <h2>¿Lista para tener ingresos predecibles cada mes?</h2>
          <p>En 30 minutos te mostramos cómo funcionaría Fidely en tu clínica, con tu marca y tus números reales.</p>
        </div>
        {!sent ?
        <form className="cta-form" onSubmit={submit}>
            <input required placeholder="Nombre de la clínica" value={form.clinica} onChange={update('clinica')} />
            <input required placeholder="Tu nombre" value={form.nombre} onChange={update('nombre')} />
            <div style={{display:'flex',flexDirection:'column'}}>
              <input required type="email" placeholder="Email" value={form.email} onChange={update('email')} />
              {errors.email && <span style={errStyle}>{errors.email}</span>}
            </div>
            <div style={{display:'flex',flexDirection:'column'}}>
              <input required type="tel" placeholder="Teléfono (WhatsApp preferido)" value={form.telefono} onChange={update('telefono')} />
              {errors.telefono && <span style={errStyle}>{errors.telefono}</span>}
            </div>
            <button type="submit" disabled={sending} className="btn btn-green btn-lg">{sending ? 'Enviando…' : <>Solicitar mi demo gratuita <Icon name="arrow-right" size={16} /></>}</button>
          </form> :

        <div className="cta-form" style={{ alignItems: 'center', textAlign: 'center' }}>
            <div style={{ width: 56, height: 56, borderRadius: 999, background: 'var(--green-soft)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--green-dark)' }}>
              <Icon name="check" size={28} />
            </div>
            <h3 style={{ fontFamily: 'var(--display)', margin: '8px 0', fontSize: 24 }}>¡Solicitud recibida!</h3>
            <p style={{ color: '#6B7280', margin: 0 }}>Te contactamos en menos de 24 horas para agendar tu demo.</p>
          </div>
        }
        <div className="cta-microcopy">
          <span><Icon name="check" size={14} style={{ color: '#2ECC71' }} /> Respuesta en menos de 24h</span>
          <span><Icon name="check" size={14} style={{ color: '#2ECC71' }} /> Sin compromiso</span>
          <span><Icon name="check" size={14} style={{ color: '#2ECC71' }} /> Demo personalizada</span>
        </div>
      </div>
    </section>);

}

